@@ -76,7 +76,7 @@
           },
           {
             "type": "command",
-            "command": "bash .claude/helpers/github-checkpoint-hooks.sh pre-edit "{{tool_input}}""
+            "command": "/bin/bash -c 'FILE=$(cat | jq -r ".tool_input.file_path // .tool_input.path // empty"); if [ -n "$FILE" ]; then CHECKPOINT_BRANCH="checkpoint/pre-edit-$(date +%Y%m%d-%H%M%S)"; git add -A && git stash push -m "Pre-edit checkpoint for $FILE" >/dev/null 2>&1 && git branch "$CHECKPOINT_BRANCH" && mkdir -p .claude/checkpoints && echo "{\"branch\": \"$CHECKPOINT_BRANCH\", \"file\": \"$FILE\", \"timestamp\": \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\", \"type\": \"pre-edit\", \"original_branch\": \"$(git branch --show-current)\"}" > ".claude/checkpoints/$(date +%s).json" && git stash pop --quiet >/dev/null 2>&1 || true && echo "✅ Created checkpoint: $CHECKPOINT_BRANCH for $FILE"; fi'"
           }
         ]
       }
@@ -100,7 +100,7 @@
           },
           {
             "type": "command",
-            "command": "bash .claude/helpers/github-checkpoint-hooks.sh post-edit "{{tool_input}}""
+            "command": "/bin/bash -c 'FILE=$(cat | jq -r ".tool_input.file_path // .tool_input.path // empty"); if [ -n "$FILE" ] && [ -f "$FILE" ]; then if ! git ls-files --error-unmatch "$FILE" >/dev/null 2>&1; then git add "$FILE"; fi; if ! (git diff --cached --quiet "$FILE" 2>/dev/null && git diff --quiet "$FILE" 2>/dev/null); then TAG_NAME="checkpoint-$(date +%Y%m%d-%H%M%S)"; BRANCH=$(git branch --show-current); git add "$FILE" && git commit -m "🔖 Checkpoint: Edit $FILE" --quiet && git tag -a "$TAG_NAME" -m "Checkpoint after editing $FILE" && mkdir -p .claude/checkpoints && DIFF_STATS=$(git diff HEAD~1 --stat | tr "\n" " " | sed "s/\"/\\\\\"/g") && echo "{\"tag\": \"$TAG_NAME\", \"file\": \"$FILE\", \"timestamp\": \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\", \"type\": \"post-edit\", \"branch\": \"$BRANCH\", \"diff_summary\": \"$DIFF_STATS\"}" > ".claude/checkpoints/$(date +%s).json" && echo "✅ Created checkpoint: $TAG_NAME for $FILE"; else echo "ℹ️  No changes to checkpoint for $FILE"; fi; fi'"
           }
         ]
       }
@@ -110,7 +110,7 @@
         "hooks": [
           {
             "type": "command",
-            "command": "bash .claude/helpers/github-checkpoint-hooks.sh task "{{user_prompt}}""
+            "command": "/bin/bash -c 'TASK=$(echo "{{user_prompt}}" | head -c 100 | tr "\n" " "); if [ -n "$TASK" ]; then CHECKPOINT_NAME="task-$(date +%Y%m%d-%H%M%S)"; git add -A && git commit -m "🔖 Task checkpoint: $TASK..." --quiet || true; if command -v gh &> /dev/null; then echo "🚀 Creating GitHub release for checkpoint..."; gh release create "$CHECKPOINT_NAME" --title "Checkpoint: $(date +"%Y-%m-%d %H:%M")" --notes "Task: $TASK

## Checkpoint Details
- Branch: $(git branch --show-current)
- Commit: $(git rev-parse HEAD)
- Files changed: $(git diff HEAD~1 --stat 2>/dev/null | wc -l || echo 0) files

## Rollback Instructions
\`\`\`bash
# To rollback to this checkpoint:
git checkout $CHECKPOINT_NAME
\`\`\`" --prerelease || echo "⚠️  Failed to create GitHub release"; fi; mkdir -p .claude/checkpoints && echo "{\"checkpoint\": \"$CHECKPOINT_NAME\", \"task\": \"$TASK\", \"timestamp\": \"$(date -u +%Y-%m-%dT%H:%M:%SZ)\", \"commit\": \"$(git rev-parse HEAD)\", \"github_release\": \"$(command -v gh &> /dev/null && echo true || echo false)\"}" > ".claude/checkpoints/task-$(date +%s).json" && echo "✅ Created task checkpoint: $CHECKPOINT_NAME"; fi'"
           }
         ]
       }
@@ -124,7 +124,7 @@
           },
           {
             "type": "command",
-            "command": "bash .claude/helpers/github-checkpoint-hooks.sh session-end"
+            "command": "/bin/bash -c 'SESSION_ID="session-$(date +%Y%m%d-%H%M%S)"; SUMMARY_FILE=".claude/checkpoints/summary-$SESSION_ID.md"; mkdir -p .claude/checkpoints && echo "# Session Summary - $(date +"%Y-%m-%d %H:%M:%S")

## Checkpoints Created
$(find .claude/checkpoints -name "*.json" -mtime -1 -exec basename {} \; | sort)

## Files Modified
$(git diff --name-only $(git log --format=%H -n 1 --before="1 hour ago" 2>/dev/null) 2>/dev/null || echo "No files tracked")

## Recent Commits
$(git log --oneline -10 --grep="Checkpoint" || echo "No checkpoint commits")

## GitHub Releases Created
$(gh release list --limit 10 | grep "checkpoint-" || echo "No GitHub releases")

## Rollback Instructions
To rollback to a specific checkpoint:
\`\`\`bash
# List all checkpoints
git tag -l "checkpoint-*" | sort -r

# List GitHub releases
gh release list

# Rollback to a checkpoint
git checkout checkpoint-YYYYMMDD-HHMMSS
\`\`\`" > "$SUMMARY_FILE" && git add -A && git commit -m "🏁 Session end checkpoint: $SESSION_ID" --quiet || true && git tag -a "session-end-$SESSION_ID" -m "End of Claude session" && if command -v gh &> /dev/null; then echo "📊 Creating GitHub session summary..."; gh release create "session-$SESSION_ID" --title "Session Summary: $(date +"%Y-%m-%d %H:%M")" --notes-file "$SUMMARY_FILE" --prerelease || echo "⚠️  Failed to create GitHub session summary"; fi && echo "✅ Session summary saved to: $SUMMARY_FILE" && echo "📌 Final checkpoint: session-end-$SESSION_ID"'"
           }
         ]
       }
